// Script Continued Below
function onLoad() {
	// STRY0079661
	g_form.setSectionDisplay('Signature',false);

	var isSuspenseDateRequired = g_scratchpad.isSuspenseDateRequired;

	if(isSuspenseDateRequired == 'true'){
		g_form.setMandatory('suspense_date',true);
	}
	// STRY0074601
	if(g_form.getValue('tasking_authority.u_external_flag') == 'true'){
			g_form.showFieldMsg("tasking_authority", getMessage('Tasker - The OU selected is an external Organizational Unit'), "info");
	}
	// STRY0109183 - Remove "Tasker Email" related list/ tab when "Disable Email Task Information" is set to true
	if(g_scratchpad.emailDiabled == true){
		g_form.hideRelatedList('x_153465_discovert_tasker_email');
	}

}
